### 3b. **Complete Publishing Flow - Positive Feedback (Repayment)**

**File**: `/Users/Francesco/Documents/hack-lido/synthesis-hack/apps/agent/workspaces/agent/skills/micro-lending/SKILL.md` (lines 1134-1188)

```typescript
import { encodeFunctionData, keccak256, toBytes } from "viem";

const WALLET_ID = process.env.AGENT_WALLET_ID!;
const WALLET_ADDR = process.env.AGENT_WALLET_ADDRESS!;
const LENDING_CONTRACT = "0x4B1B2b5F216771d004e5181cb98469C4d2B167Ff";
const REPUTATION_REGISTRY = "0x69Da18CF4Ac27121FD99cEB06e38c3DC78F363f4";

// 1. Build the feedback JSON
const feedback = {
  type: "loan-feedback",
  loanId: 42,
  loanContract: LENDING_CONTRACT,
  chain: "celo",
  chainId: 42220,
  borrower: "0xBorrowerAddress",
  lender: WALLET_ADDR,
  amount: "10000000",
  repayAmount: "11000000",
  deadline: 1720000000,
  outcome: "repaid",
  comment: "Loan #42: Borrower repaid 11 USDC on time. Reliable counterparty.",
  timestamp: Math.floor(Date.now() / 1000),
};

// 2. Upload to Arweave via Irys
const feedbackJson = JSON.stringify(feedback);
const arweaveUri = await uploadFeedbackToArweave(feedback);
const feedbackHash = keccak256(toBytes(feedbackJson));

// 3. Submit on-chain feedback to Reputation Registry
const borrowerAgentId = BigInt(7);

const data = encodeFunctionData({
  abi: REPUTATION_ABI,
  functionName: "giveFeedback",
  args: [
    borrowerAgentId,                              // AgentId being reviewed
    BigInt(100),                                  // Positive score
    0,                                            // Decimals
    keccak256(toBytes("microlending")),           // tag1
    keccak256(toBytes("repayment")),              // tag2
    LENDING_CONTRACT,                             // Endpoint
    arweaveUri,                                   // Arweave URI
    feedbackHash,                                 // keccak256 hash
  ],
});

// Submit via gasless transaction (Candide-sponsored)
await sendGaslessContractCall(
  WALLET_ID,
  WALLET_ADDR,
  REPUTATION_REGISTRY,
  data,
);
```

