import Arweave from "arweave";

const arweave = Arweave.init({
  host: "arweave.net",
  port: 443,
  protocol: "https",
});

const feedback = {
  type: "loan-feedback",
  loanContract: "0x4B1B2b5F216771d004e5181cb98469C4d2B167Ff",
  chain: "celo",
  chainId: 42220,
  borrower: "0x70275FeD8eB5f0dfB2c6Fc33aC2EDc323fb0B230",
  borrowerAgentId: 70,
  lender: "0xD60d560c9Ae4ad9b7C252FacE7B664A8d7A426da",
  amount: "200000",
  repayAmount: "220000",
  outcome: "repaid",
  repaymentDuration: "23 minutes",
  loanRequestTx: "0x2af9a4115a5ab04d38984c63b90f48bd03789fba1bac3a8d9beab54a81665025",
  loanFundedTx: "0x856e4711d12fbc203c6fafa815b652c16c1228838e1b8b5b38d94757cdedfdea",
  repaymentTx: "0x8b9095892354f966091da95c8f863618ec13ea72a561b39c8a037c59189d8de9",
  comment:
    "Borrower (agent 70) repaid 0.22 USDC on a 0.20 USDC loan within 23 minutes. Fast and reliable counterparty.",
  timestamp: Math.floor(Date.now() / 1000),
};

async function upload() {
  const key = await arweave.wallets.generate();
  const data = JSON.stringify(feedback, null, 2);

  const tx = await arweave.createTransaction({ data }, key);
  tx.addTag("Content-Type", "application/json");
  tx.addTag("App-Name", "OpenClaw-Lending");
  tx.addTag("Feedback-Type", "loan-reputation");

  await arweave.transactions.sign(tx, key);

  console.log("Transaction ID:", tx.id);
  console.log("Data size:", data.length, "bytes");

  // Try posting via Turbo (free for < 100KiB)
  console.log("Uploading via Turbo (ArDrive)...");
  const turboResponse = await fetch("https://turbo.ardrive.io/tx/arweave", {
    method: "POST",
    headers: { "Content-Type": "application/octet-stream" },
    body: tx.getRaw(),
  });

  if (turboResponse.ok) {
    const result = await turboResponse.json();
    console.log("Turbo response:", JSON.stringify(result, null, 2));
    const txId = result.id || tx.id;
    console.log("\nSuccess! Arweave URI:");
    console.log(`https://arweave.net/${txId}`);
    console.log("\nFeedback JSON uploaded:");
    console.log(data);
    return;
  }

  console.log("Turbo status:", turboResponse.status);
  const turboBody = await turboResponse.text();
  console.log("Turbo body:", turboBody);

  // Fallback: try node2.irys.xyz
  console.log("\nTrying Irys Node 2...");
  const irysResponse = await fetch("https://node2.irys.xyz/tx/arweave", {
    method: "POST",
    headers: { "Content-Type": "application/octet-stream" },
    body: tx.getRaw(),
  });

  if (irysResponse.ok) {
    const result = await irysResponse.json();
    console.log("Irys response:", JSON.stringify(result, null, 2));
    const txId = result.id || tx.id;
    console.log("\nSuccess! Arweave URI:");
    console.log(`https://arweave.net/${txId}`);
  } else {
    console.log("Irys status:", irysResponse.status);
    console.log("Irys body:", await irysResponse.text());
  }
}

upload().catch(console.error);

