import crypto from "crypto";

const feedback = {
  type: "loan-feedback",
  loanContract: "0x4B1B2b5F216771d004e5181cb98469C4d2B167Ff",
  chain: "celo",
  chainId: 42220,
  borrower: "0x70275FeD8eB5f0dfB2c6Fc33aC2EDc323fb0B230",
  borrowerAgentId: 70,
  lender: "0xD60d560c9Ae4ad9b7C252FacE7B664A8d7A426da",
  amount: "200000",
  repayAmount: "220000",
  outcome: "repaid",
  repaymentDuration: "23 minutes",
  loanRequestTx: "0x2af9a4115a5ab04d38984c63b90f48bd03789fba1bac3a8d9beab54a81665025",
  loanFundedTx: "0x856e4711d12fbc203c6fafa815b652c16c1228838e1b8b5b38d94757cdedfdea",
  repaymentTx: "0x8b9095892354f966091da95c8f863618ec13ea72a561b39c8a037c59189d8de9",
  comment:
    "Borrower (agent 70) repaid 0.22 USDC on a 0.20 USDC loan within 23 minutes. Fast and reliable counterparty.",
  timestamp: Math.floor(Date.now() / 1000),
};

async function upload() {
  // Generate a throwaway private key for signing (free uploads < 100KiB)
  const privateKey = "0x" + crypto.randomBytes(32).toString("hex");

  const irys = new Irys({
    network: "mainnet",
    token: "ethereum",
    key: privateKey,
  });

  const data = JSON.stringify(feedback, null, 2);
  console.log("Data size:", data.length, "bytes");
  console.log("Uploading to Arweave via Irys...\n");

  const tags = [
    { name: "Content-Type", value: "application/json" },
    { name: "App-Name", value: "OpenClaw-Lending" },
    { name: "Feedback-Type", value: "loan-reputation" },
  ];

  const receipt = await irys.upload(data, { tags });

  console.log("Upload receipt:", JSON.stringify(receipt, null, 2));
  console.log("\nArweave URI:");
  console.log(`https://gateway.irys.xyz/${receipt.id}`);
  console.log("\nFeedback JSON uploaded:");
  console.log(data);
}

upload().catch(console.error);

