**File:** `/Users/Francesco/Documents/hack-lido/synthesis-hack/packages/contracts/script/GiveFeedback.s.sol` (lines 6-44)

This is a Forge script showing how `giveFeedback` is called in practice:

```solidity
interface IReputationRegistry {
    function giveFeedback(
        uint256 agentId,
        int256 value,
        uint8 decimals,
        bytes32 tag1,
        bytes32 tag2,
        string calldata endpoint,
        string calldata uri,
        bytes32 hash
    ) external;
}

contract GiveFeedback is Script {
    function run() external {
        uint256 pk = 0x4e43edb2ca501caf548fbe9f93a63da9438397548e18c6caa12a1129616778cf;

        IReputationRegistry registry = IReputationRegistry(
            0x69Da18CF4Ac27121FD99cEB06e38c3DC78F363f4
        );

        uint256 agentId = 70;
        int256 value = 100; // positive score
        uint8 decimals = 0;
        bytes32 tag1 = 0x94f86d50b60b611fc3a77fbf4bad8904f02ea59de83ae6145307d46098f7ae04; // keccak256("microlending")
        bytes32 tag2 = 0x7eadba9ece915ff84585305cf923805dfabff3c3253f1e96feea1ea5db9d25fe; // keccak256("repayment")
        string memory endpoint = "0x4B1B2b5F216771d004e5181cb98469C4d2B167Ff";
        string memory uri = "https://gateway.irys.xyz/Q6O7Xhwq3FWrnkakZHNSNzRvCxIK8hzJMSr7InTwRsQ";
        bytes32 feedbackHash = 0xc2342d9dbcd500c467bb537b4c547ce3f2914f850e4b95023bd7274818c47bc0;

        vm.startBroadcast(pk);
        registry.giveFeedback(agentId, value, decimals, tag1, tag2, endpoint, uri, feedbackHash);
        vm.stopBroadcast();

        console.log("Feedback submitted for agent", agentId);
    }
}
```

**Key Parameters:**
- `agentId`: The agent receiving the feedback (uint256)
- `value`: Positive/negative integer score (int256)
- `decimals`: Precision for the score (uint8)
- `tag1, tag2`: Categorization tags (bytes32 hashes, e.g., keccak256("microlending"))
- `endpoint`: Associated contract/endpoint address (string)
- `uri`: Data reference URI (string, e.g., Irys IPFS gateway)
- `hash`: Content hash for verification (bytes32)

