### 3c. Delegation Step - EIP-712 Signing
**File:** `/Users/francesco/Documents/hack-lido/synthesis-hack/apps/web/src/app/api/agent-id/delegate/route.ts` (lines 1-127)

This is the critical step - after Self registration, delegation signs an EIP-712 message:

```typescript
const EIP712_DOMAIN = {
    name: "SelfAgentRegistry",
    version: "1",
    chainId: 42220, // Celo mainnet
    verifyingContract: REGISTRY_ADDRESS,
} as const;

const AGENT_WALLET_SET_TYPES = {
    AgentWalletSet: [
        { name: "agentId", type: "uint256" },
        { name: "newWallet", type: "address" },
        { name: "owner", type: "address" },
        { name: "nonce", type: "uint256" },
        { name: "deadline", type: "uint256" },
    ],
} as const;

// POST /api/agent-id/delegate
// Body: { agentId, walletId, walletAddress, ownerAddress }
// Returns: { signature, newWallet, deadline, nonce }

// Signs the EIP-712 message using Privy agent wallet (EOA)
const signature = await account.signTypedData({
    domain: EIP712_DOMAIN,
    types: AGENT_WALLET_SET_TYPES,
    primaryType: "AgentWalletSet",
    message: {
        agentId: BigInt(agentId),
        newWallet,
        owner,
        nonce,
        deadline,
    },
});
```

**Registry Address:** `0xaC3DF9ABf80d0F5c020C06B04Cced27763355944`

